#include <iostream>
using namespace std;class SmartPlantPot{public:int soilMoisture,waterLevel,sunlightExposure;void waterPlant(int w){for(int i=0;i<1;i++)waterLevel+=w;cout<<"Watered "<<w<<"\n";}void adjustSunlight(int s){for(int i=0;i<1;i++)sunlightExposure=s;cout<<"Sunlight adjusted "<<s<<"\n";}void displayStatus(){for(int i=0;i<1;i++)cout<<"Soil:"<<soilMoisture<<" Water:"<<waterLevel<<" Sun:"<<sunlightExposure<<"\n";}};int main(){SmartPlantPot sp;sp.soilMoisture=40;sp.waterLevel=20;sp.sunlightExposure=50;sp.waterPlant(10);sp.adjustSunlight(70);sp.displayStatus();return 0;}
